/**
 * Avalia uma string de função matemática (estilo Python/NumPy) em um ponto x.
 * Suporta: **, sin, cos, tan, sqrt, log (natural), exp, abs, pi, e
 */
export function avaliarFuncao(str, xVal) {
  try {
    const expr = str
      .trim()
      .replace(/\^/g, "**");

    /* eslint-disable no-new-func */
    const fn = new Function(
      "x",
      `const sin=Math.sin,cos=Math.cos,tan=Math.tan,` +
      `sqrt=Math.sqrt,exp=Math.exp,log=Math.log,` +
      `abs=Math.abs,pi=Math.PI,e=Math.E,PI=Math.PI,E=Math.E;` +
      `return (${expr});`
    );
    /* eslint-enable no-new-func */

    const val = fn(xVal);
    return Number.isFinite(val) ? val : NaN;
  } catch {
    return NaN;
  }
}

/** Gera N pontos igualmente espaçados em [min, max] e avalia f(x). */
export function gerarCurva(str, xMin, xMax, n = 300) {
  const pontos = [];
  for (let i = 0; i <= n; i++) {
    const x = xMin + (i / n) * (xMax - xMin);
    const y = avaliarFuncao(str, x);
    pontos.push({ x, y });
  }
  return pontos.filter(p => Number.isFinite(p.y));
}
